// // This module selects the input based on the value of sel
// If sel is 0, it outputs the logical OR of a and b; if sel is 1, it outputs the logical AND of a and b; if sel is 2, it outputs a.

module mux_3input_behavioral (
  input [1:0] sel,
  input a,
  input b,
  output reg out
);

  always @(*) begin
    if(sel == 0)
      out = a;
    else if(sel == 1)
      out = b;
    else if(sel == 2)
      out = a & b;
  end

endmodule
